def brute_force_find_operating_law(data):
    from itertools import product

    # Generate all possible pairs of inputs and their corresponding outputs
    input_pairs = list(product([0, 1, 2, 3], repeat=2))

    for a, b in input_pairs:
        observed_output = None

        for x, y in data:
            if isinstance(x, int):
                x = [x]
            if isinstance(y, int):
                y = [y]

            # Check all combinations of inputs
            for i1, i2 in product([a, b], repeat=2):
                if (i1 == a and i2 == b) or (i1 == b and i2 == a):
                    continue

                output = sum(x[i1] * y[i2] for x, y in zip(data[0][0], data[0][1]))

                # If we have an observed_output, break out of the loop
                if observed_output is not None:
                    break

            if observed_output is not None:
                continue

            # Assign the output to be used for comparison
            observed_output = output

    # Find the pair (a, b) that matches all observations
    for a, b in input_pairs:
        found_all = True

        for x, y in data:
            if isinstance(x, int):
                x = [x]
            if isinstance(y, int):
                y = [y]

            output = sum(x[i1] * y[i2] for i1, i2 in zip([a], [b]))

            # Check if the observed_output matches the calculated one
            if output != observed_output:
                found_all = False
                break

        if found_all:
            return a, b

