    # Initialize a dictionary to store the observed outputs for each unique input combination
    output_dict = {}

    # Iterate over all observations and populate the output_dict
    for inputs, expected_output in observations:
        if isinstance(inputs, list) or isinstance(inputs, tuple):
            key = tuple(sorted(inputs))
        else:
            key = (inputs,)

        if key not in output_dict:
            output_dict[key] = []
        output_dict[key].append(expected_output)

    # Function to find the operating law
    def operating_law(inputs):
        inputs_tuple = tuple(sorted(inputs)) if isinstance(inputs, list) or isinstance(inputs, tuple) else (inputs,)

        if inputs_tuple in output_dict:
            return sum(output_dict[inputs_tuple])
        else:
            raise ValueError(f"No observed data for input {inputs_tuple}")

    # Test the operating_law function with all observations
    for inputs, expected_output in observations:
        assert operating_law(inputs) == expected_output

    return operating_law

